theme.cssVars:
:root {
  /* Main Colors */
  --background: #0f1118;
  --foreground: #e2e8f0;
  --card: #1a1d2e;
  --card-border: #2a2d3e;
  --muted: #64748b;

  /* Accent Colors */
  --accent: #c89b3c;
  --accent-dim: #785a28;
  --accent-glow: rgba(200, 155, 60, 0.15);

  /* Semantic Colors */
  --win: #22c55e;
  --neutral: #eab308;
  --loss: #ef4444;
  --gap: #dc2626;

  /* Typography */
  --font-sans: 'Geist Sans', system-ui, sans-serif;
  --font-mono: 'Geist Mono', ui-monospace, monospace;

  /* Spacing Base */
  --spacing-base: 4px;

  /* Interactions */
  --focus-ring-width: 2px;
  --focus-ring-color: var(--accent);
  --focus-ring-offset: 2px;
}
